import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"S3、Bucket、Object、Key 与 Presigned URL","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"s3-object-presigned-url"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/16-s3-object-presigned-url.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/16-s3-object-presigned-url.md","lastUpdated":null}'),l={name:"05-backend-data/notes/07-cache-messaging-storage/16-s3-object-presigned-url.md"};function o(d,e,n,c,s,h){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="s3、bucket、object、key-与-presigned-url" tabindex="-1">S3、Bucket、Object、Key 与 Presigned URL <a class="header-anchor" href="#s3、bucket、object、key-与-presigned-url" aria-label="Permalink to &quot;S3、Bucket、Object、Key 与 Presigned URL&quot;">​</a></h1><p>对象存储以 bucket 和 object key 组织不可随机修改的对象。Presigned URL 是使用签名者权限生成的限时请求能力，不是一次性链接；服务端必须先授权业务对象，再限制 key、方法、过期、大小和校验和。</p><h2 id="_1-数据流与责任边界" tabindex="-1">1. 数据流与责任边界 <a class="header-anchor" href="#_1-数据流与责任边界" aria-label="Permalink to &quot;1. 数据流与责任边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A[&quot;客户端/生产者&quot;] --&gt; B[&quot;授权与受控元数据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B --&gt; C[&quot;对象存储&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C --&gt; D[&quot;异步处理/验证&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> D --&gt; E[&quot;业务发布与审计&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Presigned URL 只授权一次受约束的对象存储请求，不授予业务对象所有权。签名必须绑定服务端生成的 key、方法、必要请求头和短有效期；上传完成后仍由 upload 记录、对象版本与校验结果决定是否发布，下载前仍要重新检查业务权限。</p><h2 id="_2-bucket" tabindex="-1">2. Bucket <a class="header-anchor" href="#_2-bucket" aria-label="Permalink to &quot;2. Bucket&quot;">​</a></h2><p>机制：对象命名空间、策略、版本和生命周期边界。</p><p>使用：按环境/数据分类而非每用户建桶。</p><p>失败：公开策略或跨环境混用。</p><p>验证：策略模拟和匿名访问测试。</p><p>取舍：桶少易治理但隔离需prefix/策略。</p><p>围绕 Bucket 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_3-object" tabindex="-1">3. Object <a class="header-anchor" href="#_3-object" aria-label="Permalink to &quot;3. Object&quot;">​</a></h2><p>机制：正文、系统metadata、用户metadata和可选version组成。</p><p>使用：保存文件、导出、备份。</p><p>失败：把对象当可局部事务更新的行。</p><p>验证：HEAD/GET校验长度、checksum、version。</p><p>取舍：高耐久但小对象请求成本。</p><p>围绕 Object 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_4-key" tabindex="-1">4. Key <a class="header-anchor" href="#_4-key" aria-label="Permalink to &quot;4. Key&quot;">​</a></h2><p>机制：UTF-8对象标识，斜杠只是prefix惯例。</p><p>使用：使用随机ID/内容hash，原文件名放metadata。</p><p>失败：直接采用用户路径导致覆盖/遍历语义混乱。</p><p>验证：规范化生成并做tenant授权。</p><p>取舍：稳定key便于引用但改名是copy+delete。</p><p>围绕 Key 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_5-prefix" tabindex="-1">5. Prefix <a class="header-anchor" href="#_5-prefix" aria-label="Permalink to &quot;5. Prefix&quot;">​</a></h2><p>机制：列举和策略常用逻辑分组。</p><p>使用：tenant/date/type分区。</p><p>失败：把prefix当真正目录/权限继承。</p><p>验证：ListObjects分页与策略测试。</p><p>取舍：层次清楚但热点规则依实现。</p><p>围绕 Prefix 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_6-putobject" tabindex="-1">6. PutObject <a class="header-anchor" href="#_6-putobject" aria-label="Permalink to &quot;6. PutObject&quot;">​</a></h2><p>机制：整体写一个对象，成功后产生新对象/版本。</p><p>使用：小中等文件上传。</p><p>失败：同key会覆盖当前版本。</p><p>验证：使用条件写、versioning和checksum。</p><p>取舍：简单但大文件重试成本高。</p><p>围绕 PutObject 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_7-getobject-headobject" tabindex="-1">7. GetObject/HeadObject <a class="header-anchor" href="#_7-getobject-headobject" aria-label="Permalink to &quot;7. GetObject/HeadObject&quot;">​</a></h2><p>机制：GET取正文，HEAD取metadata。</p><p>使用：下载和存在/版本检查。</p><p>失败：用LIST确认权限或存在性。</p><p>验证：按精确key授权并检查状态。</p><p>取舍：HEAD省带宽但仍计请求。</p><p>围绕 GetObject/HeadObject 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_8-presigned-url" tabindex="-1">8. Presigned URL <a class="header-anchor" href="#_8-presigned-url" aria-label="Permalink to &quot;8. Presigned URL&quot;">​</a></h2><p>机制：SigV4把method、bucket/key、过期和签名头绑定。</p><p>使用：浏览器直传/限时下载。</p><p>失败：认为URL只能使用一次或签名即业务授权。</p><p>验证：重复使用、过期、篡改header测试。</p><p>取舍：减轻应用带宽但URL泄露即能力泄露。</p><p>围绕 Presigned URL 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_9-iam-policy" tabindex="-1">9. IAM/Policy <a class="header-anchor" href="#_9-iam-policy" aria-label="Permalink to &quot;9. IAM/Policy&quot;">​</a></h2><p>机制：身份策略、bucket policy、access point等共同决定。</p><p>使用：最小权限和环境隔离。</p><p>失败：允许任意key后仅靠应用隐藏。</p><p>验证：Access Analyzer/策略测试和审计。</p><p>取舍：精细但显式deny/条件复杂。</p><p>围绕 IAM/Policy 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_10-checksum" tabindex="-1">10. Checksum <a class="header-anchor" href="#_10-checksum" aria-label="Permalink to &quot;10. Checksum&quot;">​</a></h2><p>机制：上传时校验传输完整性，S3支持多种算法。</p><p>使用：客户端与服务端确认正文未损坏。</p><p>失败：把ETag普遍当MD5。</p><p>验证：使用ChecksumSHA256/CRC等官方字段。</p><p>取舍：增加计算但提供明确完整性。</p><p>围绕 Checksum 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_11-metadata" tabindex="-1">11. Metadata <a class="header-anchor" href="#_11-metadata" aria-label="Permalink to &quot;11. Metadata&quot;">​</a></h2><p>机制：Content-Type/Disposition和自定义metadata描述对象。</p><p>使用：下载表现、hash、业务版本。</p><p>失败：信任客户端Content-Type或在metadata放secret。</p><p>验证：服务端重判类型并最小化metadata。</p><p>取舍：便于HEAD但metadata修改通常需copy。</p><p>围绕 Metadata 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>收益</th><th>边界</th></tr></thead><tbody><tr><td>服务端代理上传</td><td>集中校验</td><td>占应用带宽</td></tr><tr><td>Presigned PUT</td><td>客户端直传</td><td>单对象与header约束</td></tr><tr><td>Presigned POST</td><td>表单policy条件</td><td>客户端实现复杂</td></tr><tr><td>公开URL</td><td>简单分发</td><td>无法按用户撤权</td></tr><tr><td>短期下载URL</td><td>最小暴露</td><td>URL泄露窗口</td></tr></tbody></table><h2 id="_13-完整案例-头像直传" tabindex="-1">13. 完整案例：头像直传 <a class="header-anchor" href="#_13-完整案例-头像直传" aria-label="Permalink to &quot;13. 完整案例：头像直传&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>最大10MiB，只允许JPEG/PNG；用户不能覆盖他人对象；上传后扫描才可见。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>API认证后生成随机object ID和quarantine key。</li><li>创建upload记录并签固定key、短过期、checksum与允许headers。</li><li>客户端直传后回调object ID而非任意key。</li><li>worker HEAD/GET验证大小、magic bytes、checksum并扫描。</li><li>通过后copy/标记到clean版本，数据库事务发布引用。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>未扫描对象不可下载，业务引用由数据库授权。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>篡改key/header/过期失败；伪Content-Type被magic检测拒绝；跨tenant不可签。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>只凭客户端回调URL入库会引用攻击者对象；服务端必须根据受控upload记录验证。</p><h3 id="恢复要求" tabindex="-1">恢复要求 <a class="header-anchor" href="#恢复要求" aria-label="Permalink to &quot;恢复要求&quot;">​</a></h3><p>回调超时后，worker 对 upload 记录中的精确 key 执行 <code>HeadObject</code>，核对长度、checksum 和 version，再用状态条件更新完成发布。重复回调以 upload ID 幂等处理；清理任务只删除记录为该 upload 生成且仍处于 quarantine 的孤儿版本，不能根据客户端文件名猜测 key。</p><h2 id="_14-完整案例-私有报表下载" tabindex="-1">14. 完整案例：私有报表下载 <a class="header-anchor" href="#_14-完整案例-私有报表下载" aria-label="Permalink to &quot;14. 完整案例：私有报表下载&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>报表含PII，下载权限可撤销，URL有效5分钟，CDN不得公开缓存。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>API每次检查tenant、owner和报表状态。</li><li>对精确version key签GET，Content-Disposition使用安全文件名。</li><li>响应不写URL到普通日志，页面避免第三方Referer泄露。</li><li>下载审计记录主体、object ID、version，不记录签名query。</li><li>撤权后停止签新URL，必要时轮换/删除对象版本。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>持有短期URL者在窗口内可下载，过期后需重新授权。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>无权不能取得URL；URL参数篡改失败；缓存头不公开。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>Presigned URL不是一次性，撤权后已签URL仍可用到过期；高风险场景缩短过期或经授权代理。</p><h3 id="恢复要求-1" tabindex="-1">恢复要求 <a class="header-anchor" href="#恢复要求-1" aria-label="Permalink to &quot;恢复要求&quot;">​</a></h3><p>签名服务失败不改变报表状态，客户端重新请求时再次鉴权并生成新 URL。已签 URL 通常不能逐条撤销，因此撤权后先停止签发；高风险下载使用更短 TTL 或授权代理。删除或轮换时按报表记录中的 object ID 与 version 操作，避免误删同 key 的其他版本。</p><h2 id="_15-故障注入矩阵" tabindex="-1">15. 故障注入矩阵 <a class="header-anchor" href="#_15-故障注入矩阵" aria-label="Permalink to &quot;15. 故障注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入</th><th>预期</th><th>禁止</th></tr></thead><tbody><tr><td>签名后撤权</td><td><code>put_errors</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>上传中断</td><td><code>get_p95</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>同key并发写</td><td><code>signature_denied</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>checksum错误</td><td><code>checksum_mismatch</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>扫描器崩溃</td><td><code>quarantine_age</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>生命周期延迟</td><td><code>anonymous_access_findings</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>对象存储429/503</td><td><code>bytes_uploaded</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>数据库提交后断线</td><td><code>orphan_objects</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr></tbody></table><h2 id="_16-调试与观测" tabindex="-1">16. 调试与观测 <a class="header-anchor" href="#_16-调试与观测" aria-label="Permalink to &quot;16. 调试与观测&quot;">​</a></h2><ol><li><code>put_errors</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>get_p95</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>signature_denied</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>checksum_mismatch</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>quarantine_age</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>anonymous_access_findings</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>bytes_uploaded</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>orphan_objects</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>presign_ttl</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>audit_downloads</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li></ol><p>上传故障按 upload ID 依次核对 owner/state、已签 method/key/headers/TTL、<code>HeadObject</code> 返回的 metadata/version/checksum 和发布条件；下载故障按 object ID 核对当前授权与签名时钟。日志只记录签名请求的结构化摘要和错误码，不记录签名 query、临时凭据或敏感正文。</p><h2 id="_17-s3兼容实现边界" tabindex="-1">17. S3兼容实现边界 <a class="header-anchor" href="#_17-s3兼容实现边界" aria-label="Permalink to &quot;17. S3兼容实现边界&quot;">​</a></h2><ol><li>确认签名算法、canonical request、region 与 endpoint 规则；path-style 和 virtual-hosted-style 不能想当然互换。</li><li>验证被签入的 <code>Content-Type</code>、checksum、SSE 等请求头是否必须由客户端原样发送，以及代理是否会改写。</li><li>测试 URL 过期边界、服务端时钟偏差和长上传开始后跨过过期时间的行为。</li><li>明确支持哪些 checksum 算法、校验发生在传输还是对象落盘阶段，以及失败时返回的错误码。</li><li>若业务依赖 version ID 或 <code>If-Match</code>，必须验证条件请求、并发覆盖和 delete marker 的实际语义。</li><li>区分签名 URL 的过期时间与底层临时凭据的过期时间；任一先到都可能使请求失败。</li><li>验证 bucket policy 中 prefix、来源网络、TLS、对象标签等条件键是否受支持且作用于目标 API。</li><li>使用 SSE-KMS 时，签名者、上传者和读取者需要的 KMS 权限不同，需分别做拒绝测试。</li><li>检查 301/307 重定向、反向代理 Host 改写和自定义域名是否破坏签名。</li><li>只对业务实际使用的 <code>HEAD</code>、<code>LIST</code> 分页与读后可见性建立集成测试，不用“S3兼容”替代行为验证。</li></ol><h2 id="_18-生产检查" tabindex="-1">18. 生产检查 <a class="header-anchor" href="#_18-生产检查" aria-label="Permalink to &quot;18. 生产检查&quot;">​</a></h2><ol><li>API 只接受 object ID，bucket 与随机 key 均从服务端 upload 记录取得。</li><li>PUT 签名固定 method、key、checksum、必要 headers 和最大 TTL，篡改测试必须返回拒绝。</li><li>客户端回调后通过 <code>HeadObject</code> 核对 size、checksum 和 version，不信任回传 URL。</li><li>GET 签名前重新检查 tenant、owner、对象状态与当前权限，不把 URL 当长期授权。</li><li>下载 URL、签名 query、临时凭据和敏感 metadata 均经过日志脱敏测试。</li><li>临时凭据权限只覆盖指定 prefix/API，轮换与过期时的失败路径已经演练。</li><li>并发上传、重复回调与数据库断线通过 upload ID 和状态条件更新保持幂等。</li><li>对象版本与业务引用一一记录，删除操作显式指定 version，避免误删覆盖版本。</li><li>孤儿对象报告能从 upload 状态反查，并在保留窗口后按精确 key/version 回收。</li><li>集成测试覆盖时钟偏差、过期、跨租户、错误 checksum、429/503 与权限撤销。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“头像直传”并用“私有报表下载”验证不同约束。提交状态机、策略、对象清单、失败注入和观测面板。</p><ul><li>[ ] Bucket 的正常、边界、权限和失败路径均通过。</li><li>[ ] Object 的正常、边界、权限和失败路径均通过。</li><li>[ ] Key 的正常、边界、权限和失败路径均通过。</li><li>[ ] Prefix 的正常、边界、权限和失败路径均通过。</li><li>[ ] PutObject 的正常、边界、权限和失败路径均通过。</li><li>[ ] GetObject/HeadObject 的正常、边界、权限和失败路径均通过。</li><li>[ ] Presigned URL 的正常、边界、权限和失败路径均通过。</li><li>[ ] IAM/Policy 的正常、边界、权限和失败路径均通过。</li><li>[ ] 两个完整案例都可在隔离环境重复运行。</li><li>[ ] 对象存储故障不改变数据库业务不变量。</li><li>[ ] 所有孤儿、版本、parts和审计记录有保留/清理策略。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/using-presigned-url.html" target="_blank" rel="noreferrer">AWS S3 presigned URLs</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/object-keys.html" target="_blank" rel="noreferrer">AWS S3 object keys</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/checking-object-integrity.html" target="_blank" rel="noreferrer">AWS S3 integrity checking</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/using-with-s3-policy-actions.html" target="_blank" rel="noreferrer">AWS S3 policy actions</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/Welcome.html" target="_blank" rel="noreferrer">Amazon S3 consistency model</a>（访问日期：2026-07-17）</li></ul>`,117)])])}const b=a(l,[["render",o]]);export{u as __pageData,b as default};
